// // This module converts a 4-bit binary input into a 4-bit Gray code output. The conversion is triggered on the falling edge of the clock signal, with the most significant bit of the output directly reflecting the input, while the subsequent bits are calculated using the AND operation on adjacent bits of the binary input.
module top_module(
  input [3:0] B,
  input Clk,
  output reg [3:0] G
);always @(posedge Clk) begin
  G[0] = B[0];
  G[1] = B[0] ^ B[1];
  G[2] = B[1] ^ B[2];
  G[3] = B[2] ^ B[3];
end

endmodule
